import { describe, it, expect } from "vitest";
import { runScenario } from "./claim-office.js";

describe("MHPCO Claim Office", () => {
  // ---- Edge cases & simplest premium ----
  it.todo("empty item list -> premium 5 G (only the processing fee)");
  it.todo("quote with unknown item type throws (CLI exits non-zero)");

  // ---- Single main item base premiums (+ fee) ----
  it.todo("plain sword (no modifiers) -> premium 105 G (100 base + 5 fee)");
  it.todo("plain amulet -> premium 65 G");
  it.todo("plain staff -> premium 85 G");
  it.todo("plain potion -> premium 45 G");

  // ---- Components & building blocks ----
  it.todo("2 runes -> base premium 50 G (+5 fee = 55 G)");
  it.todo("3 runes -> base premium 60 G (block applies) -> 65 G");
  it.todo("4 runes -> base premium 100 G (no block) -> 105 G");
  it.todo("7 runes -> base premium 175 G -> 180 G");
  it.todo("2 runes + 1 moonstone -> base premium 75 G (no block: different types) -> 80 G");
  it.todo("3 runes + 3 moonstones -> base premium 120 G (two separate blocks) -> 125 G");

  // ---- Item-level modifiers ----
  it.todo("cursed sword (newcomer) -> premium 165 G (integration example)");
  it.todo("sword enchantment exactly 5 -> high-enchantment surcharge applies");
  it.todo("sword enchantment 4 -> no high-enchantment surcharge");
  it.todo("sword enchantment 5 AND cursed -> both surcharges apply");

  // ---- Customer-level modifiers ----
  it.todo("customer with exactly 2 years -> loyalty discount applies");
  it.todo("long-standing customer second contract cursed sword ench 7 -> premium 160 G (integration example)");

  // ---- Modifier scope on multi-item policies ----
  it.todo("cursed sword + plain amulet -> 210 G before fee (cursed surcharge applies only to cursed item)");

  // ---- Rounding ----
  it.todo("premium calc yields 197.5 -> rounded up to 198 G (favor of MHPCO)");

  // ---- Claim: standard reimbursement ----
  it.todo("regular sword damage 500 G -> payout 400 G (full reimbursement minus 100 G deductible)");
  it.todo("rune damage 200 G -> payout 100 G (no special clauses, minus deductible)");

  // ---- Claim: enchantment threshold vs dragon material ----
  it.todo("dragon-material sword enchantment 9 damage 1000 G -> payout 400 G (50% wins, then deductible)");
  it.todo("dragon-material sword enchantment 5 damage 800 G -> payout 700 G (full reimbursement, then deductible)");
  it.todo("steel sword enchantment 9 damage 1000 G -> payout 400 G (50% then deductible)");
  it.todo("dragon-material sword enchantment exactly 8 damage 1000 G -> payout 400 G");

  // ---- Claim: deductible per damage event ----
  it.todo("dragon attack damages sword (500) and amulet (300) -> payout 600 G (deductible per item)");

  // ---- Claim: cap exhaustion ----
  it.todo("sword + amulet insurance sum 1600 G cap 3200 G");
  it.todo("cursed sword cap 2000 G (based on unmodified insurance value)");
  it.todo("sword + 3 runes insurance sum 1750 G (block discount affects premium only)");
  it.todo("sword two successive claims of 1500: first payout 1400, second payout 600, cap exhausted");

  // ---- Claim: multiple items of same type ----
  it.todo("two swords -> insurance sum 2000 G cap 4000 G");
  it.todo("dragon attack damages both swords (two entries) -> each gets its own deductible");
  it.todo("damages array has more entries of a type than insured -> CLI exits non-zero");

  // ---- Claim errors ----
  it.todo("claim references item not in policy -> CLI exits non-zero");
  it.todo("claim has negative damage amount -> CLI exits non-zero");

  // ---- Payout rounding ----
  it.todo("payout calc yields 350.5 -> rounded down to 350 G (favor of MHPCO)");
});

