const PROCESSING_FEE = 5;
const FIRST_INSURANCE_RATE = 0.1;
const KNOWN_ITEM_TYPES = new Set(["sword", "amulet", "staff", "potion", "rune", "moonstone"]);

const BASE_PREMIUMS: Record<string, number> = {
  sword: 100,
  amulet: 60,
  staff: 80,
  potion: 40,
  rune: 25,
  moonstone: 25,
};

interface Item {
  type: string;
}

interface QuoteStep {
  op: "quote";
  items: Item[];
}

interface Scenario {
  customer: { yearsWithMHPCO: number };
  steps: QuoteStep[];
}

const assertKnownItemType = (item: Item): void => {
  if (!KNOWN_ITEM_TYPES.has(item.type)) {
    throw new Error(`Unknown item type: ${item.type}`);
  }
};

const itemBasePremium = (item: Item): number => BASE_PREMIUMS[item.type];

const itemPremium = (item: Item): number => {
  const base = itemBasePremium(item);
  return base + base * FIRST_INSURANCE_RATE;
};

const quoteStep = (step: QuoteStep): { premium: number } => {
  step.items.forEach(assertKnownItemType);
  const itemsTotal = step.items.reduce((sum, item) => sum + itemPremium(item), 0);
  return { premium: Math.ceil(itemsTotal + PROCESSING_FEE) };
};

export const runScenario = (input: unknown): unknown => {
  const scenario = input as Scenario;
  return { results: scenario.steps.map(quoteStep) };
};

