const PROCESSING_FEE = 5;
const FIRST_INSURANCE_RATE = 0.1;
const COMPONENT_BLOCK_SIZE = 3;
const COMPONENT_BLOCK_BASE_PREMIUM = 60;

const BASE_PREMIUMS: Record<string, number> = {
  sword: 100,
  amulet: 60,
  staff: 80,
  potion: 40,
  rune: 25,
  moonstone: 25,
};

const COMPONENT_TYPES = new Set(["rune", "moonstone"]);

interface Item {
  type: string;
}

interface QuoteStep {
  op: "quote";
  items: Item[];
}

interface Scenario {
  customer: { yearsWithMHPCO: number };
  steps: QuoteStep[];
}

const itemBasePremium = (item: Item): number => {
  const base = BASE_PREMIUMS[item.type];
  if (base === undefined) {
    throw new Error(`Unknown item type: ${item.type}`);
  }
  return base;
};

const componentsBasePremiumForType = (count: number, perItem: number): number =>
  count === COMPONENT_BLOCK_SIZE ? COMPONENT_BLOCK_BASE_PREMIUM : count * perItem;

const itemsBasePremium = (items: Item[]): number => {
  const counts: Record<string, number> = {};
  let total = 0;
  for (const item of items) {
    const base = itemBasePremium(item);
    if (COMPONENT_TYPES.has(item.type)) {
      counts[item.type] = (counts[item.type] ?? 0) + 1;
    } else {
      total += base;
    }
  }
  for (const type of Object.keys(counts)) {
    total += componentsBasePremiumForType(counts[type], BASE_PREMIUMS[type]);
  }
  return total;
};

const quoteStep = (step: QuoteStep): { premium: number } => {
  step.items.forEach(itemBasePremium); // validate types
  const itemsTotal = itemsBasePremium(step.items);
  const withFirstInsurance = itemsTotal + itemsTotal * FIRST_INSURANCE_RATE;
  return { premium: Math.ceil(withFirstInsurance + PROCESSING_FEE) };
};

export const runScenario = (input: unknown): unknown => {
  const scenario = input as Scenario;
  return { results: scenario.steps.map(quoteStep) };
};

