  customer.yearsWithMHPCO >= LOYALTY_YEARS_THRESHOLD ? basePremium * LOYALTY_DISCOUNT_RATE : 0;

const quoteStep = (step: QuoteStep, customer: Customer): { premium: number } => {
  const basePremium = itemsBasePremium(step.items);
  const surcharges = itemsSurcharges(step.items);
  const discount = policyDiscount(basePremium, customer);
  return {
    premium: Math.ceil(
      withFirstInsurance(basePremium) + surcharges - discount + PROCESSING_FEE,
    ),
  };
};

export const runScenario = (input: unknown): unknown => {
  const scenario = input as Scenario;
  return { results: scenario.steps.map((step) => quoteStep(step, scenario.customer)) };
};

