const PROCESSING_FEE = 5;
const FIRST_INSURANCE_RATE = 0.1;
const CURSE_SURCHARGE_RATE = 0.5;
const HIGH_ENCHANTMENT_SURCHARGE_RATE = 0.3;
const HIGH_ENCHANTMENT_THRESHOLD = 5;
const LOYALTY_DISCOUNT_RATE = 0.2;
const LOYALTY_YEARS_THRESHOLD = 2;
const FOLLOW_UP_DISCOUNT_RATE = 0.15;
const COMPONENT_BLOCK_SIZE = 3;
const COMPONENT_BLOCK_BASE_PREMIUM = 60;
const DEDUCTIBLE_PER_DAMAGE = 100;
const CAP_MULTIPLIER = 2;

const BASE_PREMIUMS: Record<string, number> = {
  sword: 100,
  amulet: 60,
  staff: 80,
  potion: 40,
  rune: 25,
  moonstone: 25,
};

const INSURANCE_VALUES: Record<string, number> = {
  sword: 1000,
  amulet: 600,
  staff: 800,
  potion: 400,
  rune: 250,
  moonstone: 250,
};

const COMPONENT_TYPES = new Set(["rune", "moonstone"]);

interface Item {
  type: string;
  material?: string;
  enchantment?: number;
  cursed?: boolean;
}

interface QuoteStep {
  op: "quote";
  items: Item[];
}

interface Damage {
  itemType: string;
  amount: number;
}

interface ClaimStep {
  op: "claim";
  policy: number;
  incident: { cause: string; damages: Damage[] };
}

type Step = QuoteStep | ClaimStep;

interface Customer {
  yearsWithMHPCO: number;
}

interface Scenario {
  customer: Customer;
  steps: Step[];
}

const lookupBasePremium = (type: string): number => {
  const base = BASE_PREMIUMS[type];
  if (base === undefined) {
    throw new Error(`Unknown item type: ${type}`);
  }
  return base;
};

const itemBasePremium = (item: Item): number => lookupBasePremium(item.type);

const groupBasePremium = (type: string, count: number): number => {
  if (COMPONENT_TYPES.has(type) && count === COMPONENT_BLOCK_SIZE) {
    return COMPONENT_BLOCK_BASE_PREMIUM;
  }
  return count * lookupBasePremium(type);
};

const countItemsByType = (items: Item[]): Record<string, number> => {
  const counts: Record<string, number> = {};
  for (const item of items) {
    counts[item.type] = (counts[item.type] ?? 0) + 1;
  }
  return counts;
};

const itemsBasePremium = (items: Item[]): number =>
  Object.entries(countItemsByType(items)).reduce(
    (sum, [type, count]) => sum + groupBasePremium(type, count),
    0,
  );

const itemSurcharges = (item: Item): number => {
  const base = itemBasePremium(item);
  let surcharge = 0;
  if (item.cursed) surcharge += base * CURSE_SURCHARGE_RATE;
  if ((item.enchantment ?? 0) >= HIGH_ENCHANTMENT_THRESHOLD) {
    surcharge += base * HIGH_ENCHANTMENT_SURCHARGE_RATE;
  }
  return surcharge;
};

const itemsSurcharges = (items: Item[]): number =>
  items.reduce((sum, item) => sum + itemSurcharges(item), 0);

const withFirstInsurance = (basePremium: number): number =>
  basePremium + basePremium * FIRST_INSURANCE_RATE;

const policyDiscounts = (basePremium: number, customer: Customer, quoteIndex: number): number => {
  let discount = 0;
  if (customer.yearsWithMHPCO >= LOYALTY_YEARS_THRESHOLD) {
    discount += basePremium * LOYALTY_DISCOUNT_RATE;
  }
  if (quoteIndex > 0) {
    discount += basePremium * FOLLOW_UP_DISCOUNT_RATE;
  }
  return discount;
};

const itemInsuranceValue = (item: Item): number => {
  const value = INSURANCE_VALUES[item.type];
  if (value === undefined) throw new Error(`Unknown item type: ${item.type}`);
  return value;
};

const itemsInsuranceSum = (items: Item[]): number =>
  items.reduce((sum, item) => sum + itemInsuranceValue(item), 0);

interface Policy {
  items: Item[];
  insuranceSum: number;
  remainingCap: number;
}

const quotePremium = (step: QuoteStep, customer: Customer, quoteIndex: number): number => {
  const basePremium = itemsBasePremium(step.items);
  const surcharges = itemsSurcharges(step.items);
  const discount = policyDiscounts(basePremium, customer, quoteIndex);
  return Math.ceil(withFirstInsurance(basePremium) + surcharges - discount + PROCESSING_FEE);
};

const damagePayout = (damage: Damage): number =>
  Math.max(0, damage.amount - DEDUCTIBLE_PER_DAMAGE);

const claimResult = (
  step: ClaimStep,
  policies: Map<number, Policy>,
): { payout: number; remainingCap: number } => {
  const policy = policies.get(step.policy);
  if (!policy) throw new Error(`No policy at index ${step.policy}`);
  const desired = step.incident.damages.reduce((sum, d) => sum + damagePayout(d), 0);
  const payout = Math.min(desired, policy.remainingCap);
  policy.remainingCap -= payout;
  return { payout, remainingCap: policy.remainingCap };
};

export const runScenario = (input: unknown): unknown => {
  const scenario = input as Scenario;
  const policies = new Map<number, Policy>();
  let quoteIndex = 0;
  const results = scenario.steps.map((step, index) => {
    if (step.op === "quote") {
      const premium = quotePremium(step, scenario.customer, quoteIndex);
      const insuranceSum = itemsInsuranceSum(step.items);
      policies.set(index, {
        items: step.items,
        insuranceSum,
        remainingCap: insuranceSum * CAP_MULTIPLIER,
      });
      quoteIndex++;
      return { premium };
    }
    return claimResult(step, policies);
  });
  return { results };
};

