input.oldString:
const claimResult = (
  step: ClaimStep,
  policies: Map<number, Policy>,
): { payout: number; remainingCap: number } => {
  const policy = policies.get(step.policy);
  if (!policy) throw new Error(`No policy at index ${step.policy}`);
  const desired = step.incident.damages.reduce(
    (sum, d) => sum + damagePayout(d, findInsuredItem(policy, d.itemType)),
    0,
  );
  const payout = Math.min(desired, policy.remainingCap);
  policy.remainingCap -= payout;
  return { payout, remainingCap: policy.remainingCap };
};

input.newString:
const validateDamagesWithinPolicy = (damages: Damage[], policy: Policy): void => {
  const insuredCounts: Record<string, number> = {};
  for (const item of policy.items) {
    insuredCounts[item.type] = (insuredCounts[item.type] ?? 0) + 1;
  }
  const damageCounts: Record<string, number> = {};
  for (const d of damages) {
    damageCounts[d.itemType] = (damageCounts[d.itemType] ?? 0) + 1;
  }
  for (const [type, count] of Object.entries(damageCounts)) {
    if (count > (insuredCounts[type] ?? 0)) {
      throw new Error(`More ${type} damages than insured`);
    }
  }
};

const claimResult = (
  step: ClaimStep,
  policies: Map<number, Policy>,
): { payout: number; remainingCap: number } => {
  const policy = policies.get(step.policy);
  if (!policy) throw new Error(`No policy at index ${step.policy}`);
  validateDamagesWithinPolicy(step.incident.damages, policy);
  const desired = step.incident.damages.reduce(
    (sum, d) => sum + damagePayout(d, findInsuredItem(policy, d.itemType)),
    0,
  );
  const payout = Math.min(desired, policy.remainingCap);
  policy.remainingCap -= payout;
  return { payout, remainingCap: policy.remainingCap };
};

